class Solution:
    def countRangeSum(self, nums, lower, upper):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        count = 0
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                if lower <= s <= upper:
                    count += 1
        return count

